public int change(int amount, int[] coins) {
    int[] dp = new int[amount + 1];
    dp[0] = 1; // one way to make 0 — use nothing
    for (int coin : coins) {           // outer: coins
        for (int i = coin; i <= amount; i++) { // inner: amounts
            dp[i] += dp[i - coin];
        }
    }
    return dp[amount];
}
